solution:
def swap_case(s):
    parts = []
    for c in s:
        if 'a' <= c <= 'z':
            parts.append(chr(ord(c) - 32))
        elif 'A' <= c <= 'Z':
            parts.append(chr(ord(c) + 32))
        else:
            parts.append(c)
    return "".join(parts)

